"use strict";(self.webpackChunktech_far_hub=self.webpackChunktech_far_hub||[]).push([[4163],{8607:function(e,t,n){n.r(t),n.d(t,{Head:function(){return d},default:function(){return u}});var i=n(1151),r=n(7294);function a(e){const t=Object.assign({ul:"ul",li:"li",h2:"h2",hr:"hr",h3:"h3",p:"p",img:"img",strong:"strong",h4:"h4",em:"em"},(0,i.ah)(),e.components),{Summary:n}=t;return n||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Summary",!0),r.createElement(r.Fragment,null,r.createElement(n,null,r.createElement(t.ul,null,"\n",r.createElement(t.li,null,"Statement of objectives (SOO) define outcomes which allows industry to provide innovative solutions that are measured under a quality assurance surveillance plan."),"\n",r.createElement(t.li,null,"Product visions capture requirements and priorities at a high level, which establishes a high level definition of the scope of the project, specifies expected outcomes, and produces high level budgetary estimates."),"\n")),"\n",r.createElement(t.h2,{id:"agile-requirements-development"},"Agile Requirements Development"),"\n",r.createElement(t.hr),"\n",r.createElement("a",{name:"requirements"}),"\n",r.createElement(t.h3,{id:"far-15203-requires-agencies-to-identify-requirements-in-their-requests-for-proposals-rfps--how-does-this-requirement-fit-with-agile-processes-which-are-based-on-the-premise-that-it-is-not-realistic-to-expect-users-to-know-exactly-what-they-need-before-they-see-it-and-rely-on-refinement-of-system-requirements-based-on-testing-and-customer-feedback-after-the-contract-is-awarded"},"FAR 15.203 requires agencies to identify requirements in their requests for proposals (RFPs).  How does this requirement fit with Agile processes, which are based on the premise that it is not realistic to expect users to know exactly what they need before they see it and rely on refinement of system requirements based on testing and customer feedback after the contract is awarded?"),"\n",r.createElement(t.p,null,"Agencies using Agile software development can meet the requirements of FAR 15.203 by identifying a Product Vision and coupling it with an explanation of how the Agile process will be used to achieve the Product Vision.  Rather than providing a set of “how to specifications” (or Requirements Traceability Matrix), the Product Vision will focus on a desired outcome, similar to performance-based contracting, which has been permitted by the FAR for many years."),"\n",r.createElement(t.p,null,"For many years the FAR has provided for performance-based service contracts, where the Government issues a statement of objectives (SOO) defining its outcomes that allows for industry to provide innovative solutions that are measured under a quality assurance surveillance plan.  This same approach is applied to contracts using an Agile software development methodology."),"\n",r.createElement(t.p,null,"Agile software development, as with any software development, requires thorough acquisition planning, which is critical to the success of an acquisition.  Lack of proper acquisition planning and failure to follow FAR subpart 7.1, can be fatal to any procurement, but especially software development procurements.  With Agile software development, requirements and priorities are captured in a high level Product Vision, which establishes a high level definition of the scope of the project, specifies expected outcomes, and produces high level budgetary estimates.  The Integrated Product Team (IPT - cross functional team), defines the core capabilities of the project which are required to meet the mission objective and provide business value.  Requirements might be stated as a SOO as used in conjunction with performance-based contracts.  The offeror would respond to the SOO with a Performance Work Statement (PWS) which details how the SOO will be fulfilled under the contract. See Appendix C: Sample Language for Government Contracts for Agile Software Development Services."),"\n",r.createElement(t.img,{src:"/assets/img/techfar4.png",alt:"A Diagram of Showing How Product Vision Is Broken Into Manageable Pieces that Deliver Incremental Value",title:"Product Vision"}),"\n",r.createElement(t.p,null,r.createElement(t.strong,null,"A typical format for a Product Vision would specify:")),"\n",r.createElement(t.ul,null,"\n",r.createElement(t.li,null,"For (target customer)"),"\n",r.createElement(t.li,null,"Who (statement of the need or opportunity)"),"\n",r.createElement(t.li,null,"The (product name) is a (product category)"),"\n",r.createElement(t.li,null,"That (key benefit, compelling reason to buy)"),"\n",r.createElement(t.li,null,"Unlike (primary competitive alternative)"),"\n",r.createElement(t.li,null,"Our product (statement of primary differentiation)"),"\n"),"\n",r.createElement(t.h4,{id:"sample-product-visions"},"Sample Product Visions"),"\n",r.createElement(t.p,null,r.createElement(t.strong,null,"Collaboration Platform")," — For the Agency’s components that that need a collaboration platform as the primary workflow application to maintain a centralized view of all interactions and outreach to citizens engaging with the Agency through various methods.  Unlike the costly and outdated legacy systems, this new collaboration platform will replace all critical and major businesses processes with a more efficient, 21st century system at a reasonable cost."),"\n",r.createElement(t.p,null,r.createElement(t.strong,null,"Electronic Benefits System")," — For benefits recipients who need an easier way to apply for and check the status of their benefits, the electronic benefits system will allow customers to easily create and submit a new benefits application, get the status of a new application, and will allow the customer to review the status of their benefits. Unlike the old paper-based system, the electronic benefits system will provide a faster processing time and will increase the transparency into the status of the benefits application, two key needs identified by user research. We expect the new system to also address several agency needs such as increasing the ability of the agency to identify fraudulent claims, and reducing the level of effort required for an agency claims specialist to process a benefits application."),"\n",r.createElement(t.p,null,"When issuing a solicitation[",r.createElement(t.em,null,"16"),"], it should explain the Agile software development process.  The Product Owner’s high-level requirements will guide the process, and the Agency Product Owner will work together with the Agile team to develop and estimate user stories and establish acceptance criteria (specifying the expected functionality for a user story).  The Agile team will work on multiple user stories within a series of sprints which, taken together, form the software release(s) within the provided sprint/release timeframes.  The solicitation should also describe the required testing of functional requirements and make it clear that testing should be integrated into each sprint cycle.  As part of the Agile process, the Government will approve the specific plans for each iteration, establish the priorities, approve plan revisions reflecting the experience from completed iterations, and approve the working software to determine whether it meets the stated requirements."),"\n",r.createElement(t.h4,{id:"solicitation-description-of-an-agile-process"},"Solicitation Description of an Agile Process"),"\n",r.createElement(t.p,null,"“The contractor will work in a team-based Agile environment.  The Agency will create and maintain system roadmaps, project plans, and product and release backlogs that will be the basis for the contractor’s work. The Product Owner will specify high-level requirements to the Agile team. As in typical Scrum-based Agile processes, the Agency Product Owner will work together with the team to develop and estimate user stories and establish acceptance criteria. These acceptance criteria will specify expected functionality for a user story, as well as any non-functional requirements that must be met in the development of the story. The Agency Product Owner, supported by SMEs and business analysts, will determine whether or not acceptance criteria have been satisfied.”"),"\n",r.createElement(t.h2,{id:"specifying-agile-needs-in-a-manner-that-promotes-competition"},"Specifying Agile Needs in a Manner that Promotes Competition"),"\n",r.createElement(t.hr),"\n",r.createElement("a",{name:"effective-competition"}),"\n",r.createElement(t.h3,{id:"far-11002-states-that-agencies-should-specify-needs-in-a-manner-that-promotes-competition--given-that-requirements-may-not-be-fully-defined-when-the-agency-solicits-offers-and-that-not-every-offeror-knows-how-to-perform-agile-software-development-what-is-the-best-way-to-ensure-effective-use-of-competition"},"FAR 11.002 states that agencies should specify needs in a manner that promotes competition.  Given that requirements may not be fully defined when the agency solicits offers and that not every offeror knows how to perform Agile software development, what is the best way to ensure effective use of competition?"),"\n",r.createElement(t.p,null,"The Government ensures effective competition by applying a similar process used for performance-based contracting by identifying the desired outcome rather than the details of the design for how to perform the work.  There are many vendors that are well-versed in Agile software development, and that number will likely increase as agencies become more familiar with Agile processes and gain experience."),"\n",r.createElement(t.p,null,"To ensure effective use of competition, the Government must identify a Product Vision with enough information to describe the scope of the project and allow offerors to make a reasoned business judgment whether they want to compete.  This is similar to the process used for performance-based contracting where the Government develops an SOO that describes the desired outcome for the effort rather than provides instructions on how the work is to be performed."),"\n",r.createElement(t.p,null,"As in any other acquisition, requirements development should be coupled with appropriate market research and early vendor engagement (e.g., issuance of an request for information to inform the development of a solicitation, issuance of draft RFPs/RFQs, holding industry days and other mechanisms that allow prospective offerors to ask questions)."),"\n",r.createElement(t.p,null,"Simply because every vendor may not perform Agile software development does not mean that the process should be viewed as unduly restrictive of competition.  As long as the agency’s strategy is justified, it should not be at risk of such a challenge being successful.  As explained throughout this document, there are many reasons why Agile software development is beneficial in helping to manage risk and drive results.  In addition, the number of contractors that are skilled in this methodology is likely to increase as agencies become more familiar with Agile software development processes and gain experience."))}var o=function(e){void 0===e&&(e={});const{wrapper:t}=Object.assign({},(0,i.ah)(),e.components);return t?r.createElement(t,e,r.createElement(a,e)):a(e)};var s=n(5537),l=n(8173),c=n(6861),h=n(4001);const m=e=>{let{data:t,children:n,pageContext:i}=e;return t.currentPage.frontmatter&&t.siblings&&t.currentPage.tableOfContents?r.createElement(s.Z,{frontmatter:t.currentPage.frontmatter,siblings:t.siblings,tableOfContents:t.currentPage.tableOfContents,pageContext:i,useNextLink:!0},r.createElement(l.Z,null,n)):r.createElement(c.Z,null,r.createElement("h1",null,"Something went wrong"))};function u(e){return r.createElement(m,e,r.createElement(o,e))}const d=e=>{var t;let{data:n}=e;return r.createElement(h.H,{frontmatter:null===(t=n.currentPage)||void 0===t?void 0:t.frontmatter})}}}]);
